N, K = map(int, input().split())
rel = [[0] * 75 for _ in range(75)]
dp = [[-1] * 40 for _ in range(75)]
sign = ["=", "<", ">", "<=", ">="]
rev = [0, 2, 1, 4, 3]
rs = [[] for _ in range(75)]

def solve(st, pos):
    if pos > N:
        return 1
    if dp[st][pos] != -1:
        return dp[st][pos]
    en = 2 * N - (2 * (pos - 1) - st + 1)
    res = 0

    # Try placing at st and en
    valid = True
    for p in rs[st]:
        s = rel[st][p]
        if p == en or p == st:
            if s in [1, 2]:
                valid = False
        elif p < st or p > en:
            if s not in [2, 4]:
                valid = False
        else:
            if s not in [1, 3]:
                valid = False
    for p in rs[en]:
        s = rel[en][p]
        if p == st or p == en:
