                valid = False
        else:
            if s not in [1, 3]:
                valid = False
    if valid:
        res += solve(st + 1, pos + 1)

    # Try placing at st and st+1
    valid = True
    if st + 1 > en:
        valid = False
    else:
        for p in rs[st]:
            s = rel[st][p]
            if p == st + 1 or p == st:
