        for p in rs[st + 1]:
            s = rel[st + 1][p]
            if p == st or p == st + 1:
                if s in [1, 2]:
                    valid = False
            elif p < st or p > en:
                if s not in [2, 4]:
                    valid = False
            else:
                if s not in [1, 3]:
                    valid = False
    if valid:
        res += solve(st + 2, pos + 1)

    # Try placing at en-1 and en
    valid = True
    if en - 1 < st:
        valid = False
    else:
        for p in rs[en - 1]:
            s = rel[en - 1][p]
            if p == en or p == en - 1:
                if s in [1, 2]:
                    valid = False
            elif p < st or p > en:
                if s not in [2, 4]:
                    valid = False
            else:
