            if p == en - 1 or p == en:
                if s in [1, 2]:
                    valid = False
            elif p < st or p > en:
                if s not in [2, 4]:
                    valid = False
            else:
                if s not in [1, 3]:
                    valid = False
    if valid:
        res += solve(st, pos + 1)

    dp[st][pos] = res
    return res

for _ in range(K):
    a, s, b = input().split()
    a = int(a)
    b = int(b)
    x = sign.index(s)
    rs[a].append(b)
    rs[b].append(a)
    rel[a][b] = x
    rel[b][a] = rev[x]

print(solve(1, 1))
